angular.module('angularResizable', [])
    .directive('resizablelayout', function() {
        var toCall;
        function throttle(fun) {
            if (toCall === undefined) {
                toCall = fun;
                setTimeout(function() {
                    toCall();
                    toCall = undefined;
                }, 100);
            } else {
                toCall = fun;
            }
        }
        return {
            restrict: 'AE',
            scope: {
                rDirections: '=',
                rCenteredX: '=',
                rCenteredY: '=',
                rWidth: '=',
                rHeight: '=',
                rFlex: '=',
                rGrabber: '@',
                rDisabled: '@',
                rNoThrottle: '=',
                resizable: '@',
            },
            link: function(scope, element, attr) {
                if (scope.resizable === 'false') return;

                var flexBasis = 'flexBasis' in document.documentElement.style ? 'flexBasis' :
                    'webkitFlexBasis' in document.documentElement.style ? 'webkitFlexBasis' :
                    'msFlexPreferredSize' in document.documentElement.style ? 'msFlexPreferredSize' : 'flexBasis';

                // register watchers on width and height attributes if they are set
                scope.$watch('rWidth', function(value){
                    element[0].style[scope.rFlex ? flexBasis : 'width'] = scope.rWidth + 'px';
                });
                scope.$watch('rHeight', function(value){
                    element[0].style[scope.rFlex ? flexBasis : 'height'] = scope.rHeight + 'px';
                });

                element.addClass('resizable');

                var style = window.getComputedStyle(element[0], null),
                    w,
                    h,
                    dir = scope.rDirections || ['right'],
                    vx = scope.rCenteredX ? 2 : 1, // if centered double velocity
                    vy = scope.rCenteredY ? 2 : 1, // if centered double velocity
                    inner = scope.rGrabber ? scope.rGrabber : '<span></span>',
                    start,
                    dragDir,
                    axis,
                    info = {};

                var updateInfo = function(e) {
                    info.width = false; info.height = false;
                    if(axis === 'x')
                        info.width = parseInt(element[0].style[scope.rFlex ? flexBasis : 'width']);
                    else
                        info.height = parseInt(element[0].style[scope.rFlex ? flexBasis : 'height']);
                    info.id = element[0].id;
                    info.evt = e;
                };

                var getClientX = function(e) {
                    return e.touches ? e.touches[0].clientX : e.clientX;
                };

                var getClientY = function(e) {
                    return e.touches ? e.touches[0].clientY : e.clientY;
                };

                var dragging = function(e) {

                    var prop, offset = axis === 'x' ? start - getClientX(e) : start - getClientY(e);
                    switch(dragDir) {
                        case 'top':
                            prop = scope.rFlex ? flexBasis : 'height';
                            element[0].style[prop] = h + (offset * vy) + 'px';
                            break;
                        case 'bottom':
                            
                            prop = scope.rFlex ? flexBasis : 'height';
                            var newBasis = h - (offset * vy) + 'px';



                            //console.log(parseInt(element[0].style[prop], 10));
                            //console.log(parseInt(newBasis, 10));

                            if (parseInt(element[0].style[prop], 10) < parseInt(newBasis, 10)) {
                            
                                var nextElement = $("#"+element[0].id).next();
                                var heightChange = parseInt(newBasis, 10) - parseInt(element[0].style[prop], 10);
                                var parentElement = $("#"+element[0].id).parent();
                                var windowHeight = $(".columns").height();
                                
                                var totalHeight = 0;
                                parentElement.find(".box").each(function(){

                                    var flexb = $(this).css("flex-basis");
                                    totalHeight = totalHeight + parseInt($(this).css("flex-basis"), 10);

                                });
                                if (totalHeight <= (windowHeight - 250)) {
                                    element[0].style[prop] = newBasis;
                                } else {

                                   var newHeight = parseInt(nextElement.css("flex-basis")) - heightChange;

                                    if (newHeight > 0) {
                                        element[0].style[prop] = newBasis;
                                        
                                        nextElement.css("flex-basis", newHeight+"px");

                                    } else {

                                        var newHeight2 = parseInt(nextElement.next().css("flex-basis")) + newHeight;
                                        if (newHeight2 > 0) { 
                                            element[0].style[prop] = newBasis;
                                            nextElement.next().css("flex-basis", newHeight2+"px");
                                        } else {

                                            var newHeight3 = parseInt(nextElement.next().next().css("flex-basis")) + newHeight2;
                                            if (newHeight3 > 0) { 
                                                element[0].style[prop] = newBasis;
                                                nextElement.next().next().css("flex-basis", newHeight3+"px");
                                            }
                                        }

                                    }
                                }
                                

                            } else {

                                element[0].style[prop] = newBasis;

                            }                           

                            break;
                        case 'right':
                            prop = scope.rFlex ? flexBasis : 'width';
                            var newBasis = w - (offset * vx) + 'px';

                            
                            
                            if (parseInt(element[0].style[prop], 10) <= parseInt(newBasis, 10)) {

                                var nextElement = $("#"+element[0].id).next();
                                var widthChange = parseInt(newBasis, 10) - parseInt(element[0].style[prop], 10);
                                var parentElement = $("#"+element[0].id).parent();
                                var windowWidth = $(".columns").width();

			                	var totalWidth = 0;
			                    parentElement.find(".column").each(function(){
			                    	var flexb = $(this).css("flex-basis");
			                    	totalWidth = totalWidth + parseInt($(this).css("flex-basis"), 10);
			                    });

			                    if (totalWidth <= (windowWidth - 100)) {
			                    	element[0].style[prop] = newBasis;
			                    } 

                                

                            } else {
								element[0].style[prop] = newBasis;
                            }

                            break;
                        case 'left':
                            prop = scope.rFlex ? flexBasis : 'width';
                            element[0].style[prop] = w + (offset * vx) + 'px';
                            break;
                    }
                    
                    
                    updateInfo(e);
                    function resizingEmit(){
                        scope.$emit('angular-resizable.resizing', info);
                    }
                    if (scope.rNoThrottle) {
                        resizingEmit();
                    } else {
                        throttle(resizingEmit);
                    }
                    //}
                };
                var dragEnd = function(e) {
                    updateInfo();
                    scope.$emit('angular-resizable.resizeEnd', info);
                    scope.$apply();
                    document.removeEventListener('mouseup', dragEnd, false);
                    document.removeEventListener('mousemove', dragging, false);
                    document.removeEventListener('touchend', dragEnd, false);
                    document.removeEventListener('touchmove', dragging, false);
                    element.removeClass('no-transition');
                    $(".overlay-map-fix").hide();
                    sizeHeadings();
                };
                var dragStart = function(e, direction) {
                    $(".overlay-map-fix").show();
                    dragDir = direction;
                    axis = dragDir === 'left' || dragDir === 'right' ? 'x' : 'y';
                    start = axis === 'x' ? getClientX(e) : getClientY(e);
                    w = parseInt(style.getPropertyValue('width'));
                    h = parseInt(style.getPropertyValue('height'));

                    //prevent transition while dragging
                    element.addClass('no-transition');

                    document.addEventListener('mouseup', dragEnd, false);
                    document.addEventListener('mousemove', dragging, false);
                    document.addEventListener('touchend', dragEnd, false);
                    document.addEventListener('touchmove', dragging, false);

                    // Disable highlighting while dragging
                    if(e.stopPropagation) e.stopPropagation();
                    if(e.preventDefault) e.preventDefault();
                    e.cancelBubble = true;
                    e.returnValue = false;

                    updateInfo(e);
                    scope.$emit('angular-resizable.resizeStart', info);
                    scope.$apply();
                };
                if (dir) {
	                dir.forEach(function (direction) {
	                    var grabber = document.createElement('div');

	                    // add class for styling purposes
	                    grabber.setAttribute('class', 'rg-' + direction);
	                    grabber.innerHTML = inner;
	                    element[0].appendChild(grabber);
	                    grabber.ondragstart = function() { return false; };

	                    var down = function(e) {
	                        var disabled = (scope.rDisabled === 'true');
	                        if (!disabled && (e.which === 1 || e.touches)) {
	                            // left mouse click or touch screen
	                            dragStart(e, direction);
	                        }
	                    };
	                    grabber.addEventListener('mousedown', down, false);
	                    grabber.addEventListener('touchstart', down, false);
	                });
            	}
            }
        };
    });
